import { useSelector, useDispatch } from 'react-redux';
import {
  addToCart,
  removeFromCart,
  updateQuantity,
  setReservation,
} from '../store/slices/cartslice';
import { cartAPI } from '../services/api';

export const useCart = () => {
  const dispatch = useDispatch();

  // CRITICAL FIX: Destructure items directly from useSelector with a fallback.
  // This guarantees React instantly re-renders any component using this hook the millisecond Redux changes.
  const items = useSelector((state) => state.cart?.items) || [];

  const addItem = async (product, variant, quantity = 1) => {
    try {
      const cartId = localStorage.getItem('cartId') || `cart_${Date.now()}`;
      localStorage.setItem('cartId', cartId);

      const response = await cartAPI.reserve({
        product_id: product._id || product.id,
        variant_id: variant.variant_id,
        quantity,
        cart_id: cartId,
      });

      if (response.data.status === 'reserved') {
        dispatch(
          setReservation({
            productId: product._id || product.id,
            variantId: variant.variant_id,
            reservationId: response.data.reservation_id,
          })
        );
        dispatch(addToCart({ product, variant, quantity }));
        return { success: true };
      }
    } catch (error) {
      console.warn('Backend API reserve failed, falling back to local cart state.');
      // Fallback for frontend-only usage
      dispatch(addToCart({ product, variant, quantity }));
      return {
        success: true,
        error: error.response?.data?.error || 'Failed to sync with backend',
      };
    }
  };

  const removeItem = (productId, variantId) => {
    dispatch(removeFromCart({ productId, variantId }));
  };

  const changeQuantity = (productId, variantId, quantity) => {
    dispatch(updateQuantity({ productId, variantId, quantity }));
  };

  // Safe Math to prevent NaN errors
  const getCartTotal = () => {
    return items.reduce(
      (total, item) => total + (Number(item.price) || 0) * (Number(item.quantity) || 1),
      0
    );
  };

  const getItemCount = () => {
    return items.reduce((count, item) => count + (Number(item.quantity) || 1), 0);
  };

  return {
    items,
    addItem,
    removeItem,
    changeQuantity,
    getCartTotal,
    getItemCount,
  };
};
